const { supabase_url: url, supabase_key: key } = $input.first().json;
const headers = {
  apikey: key,
  Authorization: 'Bearer ' + key,
  'Content-Type': 'application/json'
};

// Circuit breaker: stop if too many recent failures
const CIRCUIT_BREAKER_THRESHOLD = 3;
const CIRCUIT_BREAKER_WINDOW_MS = 3 * 60 * 60 * 1000;

const recentFailures = await this.helpers.httpRequest({
  method: 'GET',
  url: url + '/rest/v1/pipeline_runs',
  qs: {
    triggered_by: 'eq.queue_wrapper',
    status: 'eq.failed',
    created_at: 'gte.' + new Date(Date.now() - CIRCUIT_BREAKER_WINDOW_MS).toISOString(),
    select: 'id',
    order: 'created_at.desc',
    limit: CIRCUIT_BREAKER_THRESHOLD
  },
  headers: { apikey: key, Authorization: 'Bearer ' + key },
  json: true
});

if (recentFailures && recentFailures.length >= CIRCUIT_BREAKER_THRESHOLD) {
  const recentSuccess = await this.helpers.httpRequest({
    method: 'GET',
    url: url + '/rest/v1/pipeline_runs',
    qs: {
      triggered_by: 'eq.queue_wrapper',
      status: 'eq.completed',
      created_at: 'gte.' + new Date(Date.now() - CIRCUIT_BREAKER_WINDOW_MS).toISOString(),
      select: 'id',
      limit: 1
    },
    headers: { apikey: key, Authorization: 'Bearer ' + key },
    json: true
  });

  if (!recentSuccess || recentSuccess.length === 0) {
    console.log('CIRCUIT BREAKER TRIPPED: ' + recentFailures.length + ' consecutive failures in last 3 hours with no successes. Pausing queue.');
    return [{ json: { hasMetro: false, message: 'Circuit breaker tripped: ' + recentFailures.length + ' consecutive failures in last 3 hours' } }];
  }
}

// Step 1: Find the oldest, highest-priority pending metro
const pending = await this.helpers.httpRequest({
  method: 'GET',
  url: url + '/rest/v1/pipeline_queue',
  qs: {
    status: 'eq.pending',
    or: '(retry_after.is.null,retry_after.lte.' + new Date().toISOString() + ')',
    order: 'priority.desc,queued_at.asc',
    limit: 1
  },
  headers: { apikey: key, Authorization: 'Bearer ' + key },
  json: true
});

if (!pending || pending.length === 0) {
  return [{ json: { hasMetro: false, message: 'No pending metros in queue' } }];
}

const metro = pending[0];

// Step 2: Atomically claim it (PATCH only succeeds if still pending)
const claimed = await this.helpers.httpRequest({
  method: 'PATCH',
  url: url + '/rest/v1/pipeline_queue',
  qs: {
    id: 'eq.' + metro.id,
    status: 'eq.pending'
  },
  headers: { ...headers, Prefer: 'return=representation' },
  body: {
    status: 'running',
    started_at: new Date().toISOString()
  },
  json: true
});

if (!claimed || claimed.length === 0) {
  return [{ json: { hasMetro: false, message: 'Metro claimed by another execution' } }];
}

const item = claimed[0];
return [{
  json: {
    hasMetro: true,
    queue_id: item.id,
    metro_name: item.metro_name,
    state: item.state,
    country: item.country,
    latitude: Number(item.latitude),
    longitude: Number(item.longitude),
    radius_meters: item.radius_meters,
    population: item.population,
    run_id: item.run_id,
    supabase_url: url,
    supabase_key: key
  }
}];

// Create Pipeline Run — inserts pipeline_runs row, stores run_id on queue item
// This enables the main workflow to track status via run_id lifecycle

const item = $input.item.json;
const url = item.supabase_url;
const key = item.supabase_key;
const headers = {
  apikey: key,
  Authorization: 'Bearer ' + key,
  'Content-Type': 'application/json'
};

const DEFAULT_QUERIES = 'massage therapy,massage clinic,massage therapist,spa massage,therapeutic massage,deep tissue massage,sports massage,bodywork,day spa,wellness spa,relaxation massage,licensed massage therapist';

// Parse city from metro_name (e.g., "Price, UT" -> "Price")
const city = item.metro_name.split(',')[0].trim();

console.log('Create Pipeline Run: ' + item.metro_name + ' (queue_id: ' + item.queue_id + ')');

// Step 1: INSERT pipeline_runs row
const runRow = await this.helpers.httpRequest({
  method: 'POST',
  url: url + '/rest/v1/pipeline_runs',
  headers: { ...headers, Prefer: 'return=representation' },
  body: {
    metro_name: item.metro_name,
    country: item.country || 'US',
    state: item.state,
    city: city,
    latitude: item.latitude,
    longitude: item.longitude,
    radius_meters: item.radius_meters || 15000,
    search_queries: DEFAULT_QUERIES.split(','),
    status: 'queued',
    triggered_by: 'queue_wrapper'
  },
  json: true
});

const runId = runRow[0].id;
console.log('  Created pipeline_runs: ' + runId);

// Step 2: PATCH pipeline_queue to store run_id FK
await this.helpers.httpRequest({
  method: 'PATCH',
  url: url + '/rest/v1/pipeline_queue',
  qs: { id: 'eq.' + item.queue_id },
  headers: { ...headers, Prefer: 'return=minimal' },
  body: { run_id: runId },
  json: true
});

console.log('  Linked queue_id ' + item.queue_id + ' -> run_id ' + runId);

return { json: { ...item, run_id: runId } };

// Trigger the main pipeline webhook with metro config + run_id
// Pipeline runs async; Poll Pipeline Status node watches for completion

const item = $input.item.json;
const webhookUrl = $env.MAIN_WORKFLOW_WEBHOOK_URL;

if (!webhookUrl) {
  throw new Error('MAIN_WORKFLOW_WEBHOOK_URL env var not set. Add it in Coolify.');
}

const payload = {
  metro_name: item.metro_name,
  latitude: item.latitude,
  longitude: item.longitude,
  radius_meters: item.radius_meters,
  yelp_location: item.metro_name,
  run_id: item.run_id
};

console.log('Triggering pipeline for: ' + item.metro_name + ' (run_id: ' + item.run_id + ')');

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: webhookUrl,
    headers: { 'Content-Type': 'application/json' },
    body: payload,
    json: true,
    timeout: 10000
  });
  console.log('Pipeline responded for ' + item.metro_name);
} catch (err) {
  // Timeout is EXPECTED — pipeline accepted the webhook but takes 10-30 min to complete
  // n8n webhooks don't respond until the workflow finishes (no Respond to Webhook node)
  var msg = err.message || '';
  if (msg.includes('timeout') || msg.includes('ETIMEDOUT') || msg.includes('ESOCKETTIMEDOUT') || msg.includes('ECONNRESET')) {
    console.log('Pipeline trigger accepted (timeout is normal): ' + item.metro_name);
  } else {
    throw new Error('Pipeline trigger FAILED for ' + item.metro_name + ': ' + msg);
  }
}

return { json: item };

// Poll Pipeline Status — waits for pipeline_runs to reach terminal state
// Polls every 30s for up to 45 minutes. Throws on failure/timeout.

const item = $input.item.json;
const url = item.supabase_url;
const key = item.supabase_key;
const runId = item.run_id;

if (!runId) {
  console.log('Poll Pipeline Status: no run_id, skipping');
  return { json: item };
}

const MAX_POLLS = 90;       // 90 x 30s = 45 minutes max
const POLL_INTERVAL = 30000; // 30 seconds
const delay = function(ms) { return new Promise(function(r) { setTimeout(r, ms); }); };

console.log('Poll Pipeline Status: watching run_id ' + runId + ' for ' + item.metro_name);

for (var i = 0; i < MAX_POLLS; i++) {
  var rows = await this.helpers.httpRequest({
    method: 'GET',
    url: url + '/rest/v1/pipeline_runs',
    qs: { id: 'eq.' + runId, select: 'status,completed_batches,total_batches' },
    headers: { apikey: key, Authorization: 'Bearer ' + key },
    json: true
  });

  var run = rows && rows[0];
  if (!run) {
    console.log('  Poll ' + (i+1) + ': run_id not found, waiting...');
    await delay(POLL_INTERVAL);
    continue;
  }

  console.log('  Poll ' + (i+1) + ': status=' + run.status + ', batches=' + (run.completed_batches || 0) + '/' + (run.total_batches || '?'));

  if (run.status === 'completed') {
    return {
      json: {
        ...item,
        pipeline_status: 'completed',
        completed_batches: run.completed_batches,
        total_batches: run.total_batches
      }
    };
  }

  if (run.status === 'failed') {
    throw new Error('Pipeline failed for ' + item.metro_name + ' (run_id: ' + runId + ')');
  }

  await delay(POLL_INTERVAL);
}

throw new Error('Pipeline timed out for ' + item.metro_name + ' after 45 minutes (run_id: ' + runId + ')');

// Run post-discovery cleanup, then pass through item data
const item = $input.item.json;
const url = item.supabase_url;
const key = item.supabase_key;

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: url + '/rest/v1/rpc/run_post_discovery_cleanup',
    headers: {
      apikey: key,
      Authorization: 'Bearer ' + key,
      'Content-Type': 'application/json'
    },
    body: {
      p_metro: item.metro_name,
      p_lat: item.latitude,
      p_lon: item.longitude,
      p_radius_km: item.radius_meters / 1000
    },
    json: true
  });
  console.log('Cleanup for ' + item.metro_name + ': ' + JSON.stringify(result));
} catch (err) {
  console.log('Cleanup warning for ' + item.metro_name + ': ' + err.message);
  // Non-fatal — cleanup failure should not block marking complete
}

// Pass through original item data for Mark Complete
return { json: item };

// Mark the queue item as complete
const item = $input.item.json;
const url = item.supabase_url;
const key = item.supabase_key;
const headers = {
  apikey: key,
  Authorization: 'Bearer ' + key,
  'Content-Type': 'application/json',
  Prefer: 'return=minimal'
};

try {
  // Count leads found for this metro
  const companies = await this.helpers.httpRequest({
    method: 'GET',
    url: url + '/rest/v1/companies',
    qs: {
      discovery_metro: 'eq.' + item.metro_name,
      select: 'id'
    },
    headers: { apikey: key, Authorization: 'Bearer ' + key },
    json: true
  });

  const leadsFound = companies ? companies.length : 0;

  // PATCH queue item to complete
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: url + '/rest/v1/pipeline_queue',
    qs: { id: 'eq.' + item.queue_id },
    headers: headers,
    body: {
      status: 'complete',
      completed_at: new Date().toISOString(),
      leads_found: leadsFound
    },
    json: true
  });

  console.log('Queue complete: ' + item.metro_name + ' — ' + leadsFound + ' leads found');
  return { json: { ...item, status: 'complete', leads_found: leadsFound } };

} catch (err) {
  // If marking complete fails, try to mark as failed
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: url + '/rest/v1/pipeline_queue',
      qs: { id: 'eq.' + item.queue_id },
      headers: headers,
      body: {
        status: 'failed',
        error_message: 'Mark complete failed: ' + err.message
      },
      json: true
    });
  } catch (e) { /* best effort */ }
  throw err;
}
